import{_ as r,o as t,c as n,j as e,a as s,a1 as _}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"3.18.随从与召唤物","description":"","frontmatter":{},"headers":[],"relativePath":"1.基础规则/3.战斗规则/3.18.随从与召唤物.md","filePath":"1.基础规则/3.战斗规则/3.18.随从与召唤物.md"}'),o={name:"1.基础规则/3.战斗规则/3.18.随从与召唤物.md"};function p(d,a,l,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"_3-18-随从与召唤物",tabindex:"-1"},[s("3.18.随从与召唤物 "),e("a",{class:"header-anchor",href:"#_3-18-随从与召唤物","aria-label":'Permalink to "3.18.随从与召唤物"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"灵魂蓝调013")])])],-1),_('<h1 id="随从与召唤物" tabindex="-1">随从与召唤物 <a class="header-anchor" href="#随从与召唤物" aria-label="Permalink to &quot;随从与召唤物&quot;">​</a></h1><p>随从与召唤物</p><p>随从与召唤物是人物通过资源或者专长得到的单位。通常随从与召唤物在购买时附赠一个胶囊空间（或是别的召唤方式），将它们召唤出来若无特殊说明，是一个移动动作。回收动作也是一个移动动作。<br> 这一类单位具有以下共性：<br> 1、具有自身的行动轮，随从与召唤物的行动轮与轮回者不同，他们的行动轮只有1个迅捷动作、1个移动动作、1个标准动作可供使用。<br> 2、在死亡后间隔1日方可重新召唤，重新召唤的单位生命值只有完好状态的一半。<br> 3、在随从可使用意志力的场合，人物可以支付意志力令随从获得意志力基础用法的好处，这会令随从消耗等额的意志力。需要注意的是，这不会令随从在此次行为中获得人物所具有的意志力用法的额外加值。</p><p>随从最多只能同时维持遵循一个命令，出现新的命令时，随从会优先执行最新的命令。你随时可以在符合条件的情况下为随从下达命令。</p><p>自由杀戮<br> 下令随从进行自由杀戮是一个自由动作，随从将会在它自身的回合随机选择可以在本回合中攻击到的敌对进行攻击，并会自行为此进行移动。攻击会使用随从的标准动作，它因自由杀戮而进行的攻击不会附带任何招式。</p><p>跟随指挥<br> 通常情况下随从无法使用附带招式的动作，若随从要使用招式，则人物需要消耗一个等同于招式所需动作的同类动作。举例而言：随从试图使用一个消耗标准动作的技艺，需要人物同时消耗一个标准动作才可施展。</p><p>紧急守护<br> 下令随从紧急守护是一个反射或迅捷动作，并再消耗一个移动动作（若在回合外使用，还需保有至少足够的AP进行使用）。应对一次攻击，使用一个迅捷或反射动作，消耗一个额外的移动动作，立即命令随从回归到自身身边并为主人进行守护。这意味着随从至少要保有一个移动动作，且随从可以正常移动回其主人身周风度*米数，才能正常生效。随从立即移动回符合生效范围的，由其主指定的一个位置，并会为此次攻击（若为回合内使用，则改为下一次）额外抵消等同于其主的风度/2点伤害出目，但相应的，这只随从也会同时受到抵消的这些伤害，不会计算其防御或豁免，但会正常计算伤害吸收。紧急守护一轮只能使用一次，它被视为进行了一次格挡或招架。</p><hr><p>Copyright ? 2022 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',9)])])}const m=r(o,[["render",p]]);export{f as __pageData,m as default};
